# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

def process_transactions(accounts, transactions):
    """
    Process financial transactions and update account balances.
    
    Args:
        accounts: dict mapping account_id to balance
        transactions: list of transaction dicts with keys: 'from', 'to', 'amount'
    
    Returns:
        dict: updated accounts with new balances
        list: list of transaction results (success/failure with details)
    """
    results = []
    
    for transaction in transactions:
        from_account = transaction.get('from')
        to_account = transaction.get('to')
        amount = transaction.get('amount', 0)
        
        if amount <= 0:
            results.append({
                'transaction': transaction,
                'status': 'failed',
                'reason': 'Invalid amount'
            })
            continue
        
        if from_account not in accounts:
            results.append({
                'transaction': transaction,
                'status': 'failed',
                'reason': f'Source account {from_account} not found'
            })
            continue
        
        if to_account not in accounts:
            results.append({
                'transaction': transaction,
                'status': 'failed',
                'reason': f'Destination account {to_account} not found'
            })
            continue
        
        if accounts[from_account] < amount:
            results.append({
                'transaction': transaction,
                'status': 'failed',
                'reason': 'Insufficient funds'
            })
            continue
        
        accounts[from_account] -= amount
        accounts[to_account] += amount
        
        results.append({
            'transaction': transaction,
            'status': 'success',
            'from_balance': accounts[from_account],
            'to_balance': accounts[to_account]
        })
    
    return accounts, results